/// Canonical Serial tick step.
///
/// Phases:
/// 1. Mask build (`mask_fill::fill_all`)
/// 2. Policy evaluate (`backend.evaluate`)
/// 3. Deterministic action shuffle (Fisher-Yates)
/// 4. Apply actions + cascade fixed-point
/// 5. View fold (`views.fold_all`)
/// 6. Tick advance (`state.tick += 1`)
///
/// `debug` is passed by the caller; `DebugConfig::default()` (all collectors
/// disabled) is a zero-cost no-op path — all stepper checkpoints are guarded
/// by `if let Some(stepper) = debug.tick_stepper.as_ref()`.
pub fn step<CB: ComputeBackend, B: PolicyBackend>(
    backend: &mut CB,
    state: &mut SimState,
    scratch: &mut SimScratch,
    events: &mut EventRing<Event>,
    views: &mut ViewRegistry,
    policy: &B,
    cascade: &CascadeRegistry<Event, ViewRegistry>,
    debug: &DebugConfig,
) {
    // Checkpoint: BeforeViewFold (entry — before mask build begins).
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::BeforeViewFold) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 1 — mask build.
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("mask_fill");
        }
    }
    crate::mask_fill::fill_all(backend, &mut scratch.mask, &mut scratch.target_mask, state);
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Checkpoint: AfterMaskFill.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::AfterMaskFill) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 2 — policy evaluate.
    scratch.actions.clear();
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("scoring");
        }
    }
    policy.evaluate(
        state,
        &scratch.mask,
        &scratch.target_mask,
        &mut scratch.actions,
    );
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Checkpoint: AfterScoring.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::AfterScoring) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 3 — deterministic action shuffle.
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("action_select");
        }
    }
    shuffle_actions_in_place(
        state.seed,
        state.tick,
        &scratch.actions,
        &mut scratch.shuffle_idx,
    );
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Checkpoint: AfterActionSelect.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::AfterActionSelect) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 4a — apply actions (emit root-cause events).
    let events_before = events.total_pushed();
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("cascade_dispatch");
        }
    }
    apply_actions(state, scratch, events);

    // Phase 4b — cascade fixed-point.
    cascade.run_fixed_point(state, views, events);
    let _ = events_before; // reserved for future telemetry
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Checkpoint: AfterCascadeDispatch.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::AfterCascadeDispatch) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 5b: belief decay (per-tick confidence multiply + eviction)
    {
        let decay_rate = state.config.belief.decay_rate;
        let floor = state.config.belief.eviction_threshold;
        let observers: Vec<AgentId> = state.agents_alive().collect();
        for observer in observers {
            if let Some(beliefs) = state.agent_cold_beliefs_mut(observer) {
                beliefs.retain(|_, bs| {
                    bs.confidence *= decay_rate;
                    bs.confidence >= floor
                });
            }
        }
    }

    // Phase 5 — view fold.
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("view_fold");
        }
    }
    views.fold_all(events, events_before, state.tick);
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Phase 5.5 — lazy-view recompute (stale-view repair).
    // Must run after fold_all so materialized views are populated first.
    // Marks lazy views stale when any of their invalidating events landed
    // this tick; recompute happens on next consumer access or eagerly here.
    views.invalidate_lazy_views(events, events_before);

    // Checkpoint: AfterViewFold.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::AfterViewFold) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Phase 6 — tick advance.
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.enter("tick_end");
        }
    }
    state.tick = state.tick.wrapping_add(1);
    if let Some(profile) = debug.tick_profile.as_ref() {
        if let Ok(mut p) = profile.lock() {
            p.exit_with_null();
        }
    }

    // Checkpoint: TickEnd.
    if let Some(stepper) = debug.tick_stepper.as_ref() {
        match stepper.checkpoint(engine::debug::tick_stepper::Phase::TickEnd) {
            engine::debug::tick_stepper::Step::Continue => {}
            engine::debug::tick_stepper::Step::Pause => {}
            engine::debug::tick_stepper::Step::Abort => return,
        }
    }

    // Agent history — record at TickEnd. The tick counter was already
    // incremented in Phase 6, so we pass `state.tick.wrapping_sub(1)` to
    // label the snapshot with the tick that just completed.
    if let Some(history) = debug.agent_history.as_ref() {
        if let Ok(mut h) = history.lock() {
            h.record(state.tick.wrapping_sub(1), state);
        }
    }
}

